INSERT INTO contraindications (dci_pattern,condition_type,condition_valeur,severite,description,mecanisme_fr,conduite_fr)
VALUES
('candésartan','pathologie','Hyperkaliémie sévère (> 6 mEq/L)','absolue','Candésartan aggrave l''hyperkaliémie par blocage de l''angiotensine II → rétention potassique','Réduction de l''aldostérone → rétention potassique rénale sous candésartan','CI si K+ > 6 mEq/L. Corriger hyperkaliémie avant. Kaliémie hebdomadaire initiale'),
('olmésartan','pathologie','Grossesse — 2ème et 3ème trimestre','absolue','Olmésartan fœtotoxique : même toxicité que les IEC sur le rein fœtal (anurie, oligoamnios)','Blocage du SRA fœtal par olmésartan → hypotension, anurie, malformations rénales','CI absolue après 14 SA. Substituer avant grossesse ou dès 1er trimestre si découverte'),
('olmésartan','pathologie','Grossesse — 1er trimestre','relative','Olmésartan au 1er trimestre : éviter (données limitées, possible toxicité cardiovasculaire)','SRA impliqué dans développement cardiovasculaire embryonnaire','Arrêter dès connaissance de la grossesse. Méthyldopa, labétalol, nifédipine LP en alternative'),
('olmésartan','pathologie','Allaitement','relative','Olmésartan déconseillé en allaitement : passage lacté et risque hypotension néonatale','Données lacunaires sur passage lacté des ARA2. Prudence requise','Préférer méthyldopa ou labétalol. Éviter ARA2 pendant l''allaitement'),
('olmésartan','pathologie','Hyperkaliémie sévère (> 6 mEq/L)','absolue','Olmésartan aggrave l''hyperkaliémie par blocage de l''angiotensine II → rétention potassique','Réduction de l''aldostérone → rétention potassique rénale sous olmésartan','CI si K+ > 6 mEq/L. Corriger hyperkaliémie avant. Kaliémie hebdomadaire initiale'),
